PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE `statements` (`id` INTEGER PRIMARY KEY AUTOINCREMENT, `owner_id` INTEGER NOT NULL, `owner_name` VARCHAR(255) NOT NULL, `property_id` INTEGER, `property_name` VARCHAR(255), `week_start_date` DATE NOT NULL, `week_end_date` DATE NOT NULL, `calculation_type` VARCHAR(255) NOT NULL DEFAULT 'checkout', `total_revenue` DECIMAL(10,2) NOT NULL DEFAULT 0, `total_expenses` DECIMAL(10,2) NOT NULL DEFAULT 0, `pm_commission` DECIMAL(10,2) NOT NULL DEFAULT 0, `pm_percentage` DECIMAL(5,2) NOT NULL DEFAULT 15, `tech_fees` DECIMAL(10,2) NOT NULL DEFAULT 0, `insurance_fees` DECIMAL(10,2) NOT NULL DEFAULT 0, `adjustments` DECIMAL(10,2) NOT NULL DEFAULT 0, `owner_payout` DECIMAL(10,2) NOT NULL DEFAULT 0, `is_cohost_on_airbnb` TINYINT(1) NOT NULL DEFAULT 0, `status` VARCHAR(255) NOT NULL DEFAULT 'draft', `sent_at` DATETIME, `reservations` JSON NOT NULL DEFAULT '[]', `expenses` JSON NOT NULL DEFAULT '[]', `items` JSON NOT NULL DEFAULT '[]', `duplicate_warnings` JSON NOT NULL DEFAULT '[]', `created_at` DATETIME NOT NULL, `updated_at` DATETIME NOT NULL);
CREATE TABLE `uploaded_expenses` (`id` INTEGER PRIMARY KEY AUTOINCREMENT, `property_id` INTEGER, `type` VARCHAR(255) NOT NULL DEFAULT 'other', `description` TEXT NOT NULL, `amount` DECIMAL(10,2) NOT NULL, `date` DATE NOT NULL, `source` VARCHAR(255) NOT NULL DEFAULT 'manual', `source_id` VARCHAR(255), `invoice_number` VARCHAR(255), `vendor` VARCHAR(255), `category` VARCHAR(255), `notes` TEXT, `listing` VARCHAR(255), `upload_filename` VARCHAR(255), `created_at` DATETIME NOT NULL, `updated_at` DATETIME NOT NULL);
CREATE TABLE `listings` (`id` INTEGER PRIMARY KEY, `name` VARCHAR(255) NOT NULL, `display_name` VARCHAR(255), `nickname` VARCHAR(255), `street` VARCHAR(255), `city` VARCHAR(255), `state` VARCHAR(255), `country` VARCHAR(255), `pm_fee_percentage` DECIMAL(5,2) DEFAULT 15, `is_cohost_on_airbnb` TINYINT(1) NOT NULL DEFAULT 0, `tags` TEXT, `is_active` TINYINT(1) NOT NULL DEFAULT 1, `last_synced_at` DATETIME, `created_at` DATETIME NOT NULL, `updated_at` DATETIME NOT NULL);
DELETE FROM sqlite_sequence;
CREATE INDEX `listings_name` ON `listings` (`name`);
CREATE INDEX `listings_is_active` ON `listings` (`is_active`);
COMMIT;
